// Универсальный парсер Jina AI для PubMed, научных статей и обычных веб-страниц
// Работает с PDF и веб-контентом

let content;

if (typeof $input.item.json === 'string') {
  content = $input.item.json;
} else if ($input.item.json?.data) {
  content = $input.item.json.data;
} else if ($input.item.json?.content) {
  content = $input.item.json.content;
} else if ($input.item.binary) {
  content = Buffer.from($input.item.binary.data).toString('utf-8');
} else {
  const jsonData = $input.item.json;
  const firstStringValue = Object.values(jsonData).find(
    v => typeof v === 'string' && v.length > 100
  );
  content = firstStringValue || JSON.stringify(jsonData);
}

if (typeof content !== 'string') {
  content = String(content);
}

if (!content || content.length < 100) {
  return {
    json: {
      title: null,
      abstract: null,
      publicationDate: null,
      pdfUrl: null,
      cleanContent: null,
      error: 'Content too short or empty',
    },
  };
}

// ===== ФУНКЦИЯ: Предварительная очистка контента (под PubMed и Jina-шум) =====
function preCleanContent(text) {
  return text
    .replace(/\*\*Title: How does .+ A-Z\]\(m\)/i, '') // navigation UI
    .replace(/Display options\?Format/g, '')
    .replace(/Actions\?Cite\|Collections\|Permalink/g, '')
    .replace(/Create a new collection\?Cancel/g, '')
    .replace(/Add to an existing collection\?Cancel/g, '')
    .replace(/Full text links\?Cite/g, '')
    .replace(/MeSH terms\?LinkOut/g, '')
    .replace(/Publication types\?MeSH terms/g, '')
    .replace(/Similar articles\?\?Cited by\|References/g, '')
    .replace(/References\?\?Publication types/g, '')
    .replace(/Cited by\?\?References\|Publication types/g, '')
    .replace(/Skip to main page content/g, '')
    .replace(/The \.gov means it's official\?transmitted securely\./g, '')
    .replace(/Logged in as\?Log out/g, '')
    .replace(/NCBI Literature Resources/g, '')
    .replace(/National Library of Medicine/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

content = preCleanContent(content);

// Убираем служебную информацию Jina API
content = content
  .split('\n')
  .filter(
    line =>
      !line.includes('Usage: 1') &&
      !line.includes('Usage: 2') &&
      !line.includes('r.jina.ai/YOUR-URL'),
  )
  .join('\n')
  .trim();

// ===== ФУНКЦИЯ: Очистка заголовка от мусора =====
function sanitizeTitle(title) {
  if (!title) return null;

  const badPatterns = [
    'Usage: 1',
    'Usage: 2',
    'YOUR-URL',
    'Homepage',
    'Reader API',
    'Convert a URL to LLM-friendly input',
    'jina.ai',
  ];

  const lower = title.toLowerCase();
  if (badPatterns.some(p => lower.includes(p.toLowerCase()))) {
    return null;
  }

  return title;
}

// ===== ФУНКЦИЯ: Извлечение заголовка =====
function extractTitle(text) {
  // PubMed
  const pubmedTitle = text.match(/Title: (.+?)(?=\n)/m);
  if (pubmedTitle) {
    const candidate = pubmedTitle[1].trim().replace(/ - PubMed$/, '');
    const safe = sanitizeTitle(candidate);
    if (safe) return safe;
  }

  // URL Source
  const afterUrl = text.match(/URL Source: .+?\n\n(.+?)(?=\n|$)/s);
  if (afterUrl) {
    let title = afterUrl[1].trim();
    title = title.replace(/\n.+$/, '').replace(/\|.+$/, '');
    if (title.length > 20 && title.length < 300) {
      const safe = sanitizeTitle(title);
      if (safe) return safe;
    }
  }

  // Первая разумно длинная строка
  const lines = text.split('\n').filter(l => l.trim().length > 20);
  for (const line of lines) {
    const cleaned = line.trim().replace(/^\[|\]$/g, '');
    if (
      cleaned.length > 30 &&
      cleaned.length < 300 &&
      !cleaned.startsWith('http') &&
      !cleaned.match(/\d{4}/) &&
      !cleaned.includes('PMID') &&
      !cleaned.includes('doi')
    ) {
      const safe = sanitizeTitle(cleaned);
      if (safe) return safe;
    }
  }

  return null;
}

// ===== ФУНКЦИЯ: Извлечение даты (исправленная) =====
function extractDate(text) {
  // PubMed формат: "2024 May;6(2):98014"
  const pubmedDate = text.match(
    /(\d{4})\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\b/i,
  );
  if (pubmedDate) {
    return formatDate(pubmedDate[0], pubmedDate[2], pubmedDate[1]);
  }

  // Published Time: 2023-01-08T12:08:35+03:00
  const publishedTime = text.match(
    /Published Time:\s*(\d{4})-(\d{2})-(\d{2})/,
  );
  if (publishedTime) {
    return formatDate(null, publishedTime[2], publishedTime[1], publishedTime[3]);
  }

  // Пробуем разные форматы
  const patterns = [
    /(\d{4})-(\d{2})-(\d{2})/, // YYYY-MM-DD
    /(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\s+(\d{1,2}),?\s*(\d{4})/i, // Month DD, YYYY
    /(\d{1,2})\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\s+(\d{4})/i, // DD Month YYYY
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      return formatDate(match);
    }
  }

  return null;
}

// ===== ФУНКЦИЯ: Форматирование даты в MM/DD/YYYY =====
function formatDate(match, monthArg, yearArg, dayArg) {
  const monthMap = {
    jan: '01',
    feb: '02',
    mar: '03',
    apr: '04',
    may: '05',
    jun: '06',
    jul: '07',
    aug: '08',
    sep: '09',
    oct: '10',
    nov: '11',
    dec: '12',
    '01': '01',
    '02': '02',
    '03': '03',
    '04': '04',
    '05': '05',
    '06': '06',
    '07': '07',
    '08': '08',
    '09': '09',
    '10': '10',
    '11': '11',
    '12': '12',
  };

  let day = '01',
    month,
    year;

  if (monthArg && yearArg) {
    // Вызов из pubmedDate или publishedTime
    month = monthMap[String(monthArg).toLowerCase().substring(0, 3)] || '01';
    year = yearArg;
    day = dayArg ? String(dayArg).padStart(2, '0') : '01';
  } else if (match[0].match(/\d{4}-\d{2}-\d{2}/)) {
    // YYYY-MM-DD
    year = match[1];
    month = match[2];
    day = match[3];
  } else if (match[2] && match[2].match(/\d{4}/)) {
    // Month DD, YYYY или YYYY Month
    const monthName = match[1].toLowerCase().substring(0, 3);
    month = monthMap[monthName] || '01';
    year = match[3] || match[2];
    day = match[3] ? '01' : match[2].padStart(2, '0');
  } else if (match[3]) {
    // DD Month YYYY
    day = match[1].padStart(2, '0');
    const monthName = match[2].toLowerCase().substring(0, 3);
    month = monthMap[monthName] || '01';
    year = match[3];
  }

  // ✅ ВОЗВРАЩАЕМ В ФОРМАТЕ MM/DD/YYYY
  return `${month}/${day}/${year}`;
}

// ===== ФУНКЦИЯ: Извлечение PDF URL =====
function extractPdfUrl(text) {
  // Прямая ссылка на PDF
  const pdfLink = text.match(/(https?:\/\/.+?\.pdf)/i);
  if (pdfLink) return pdfLink[0];

  // PMC PDF
  const pmcLink = text.match(
    /https?:\/\/www\.ncbi\.nlm\.nih\.gov\/pmc\/articles\/(PMC\d+)/,
  );
  if (pmcLink)
    return `https://www.ncbi.nlm.nih.gov/pmc/articles/${pmcLink[1]}/pdf`;

  // DOI
  const doiLink = text.match(/doi:(10\.\d{4,}\/[^\s]+)/i);
  if (doiLink) return `https://doi.org/${doiLink[1]}`;

  return null;
}

// ===== УНИВЕРСАЛЬНАЯ ДОЧИСТКА ВЕБ-КОНТЕНТА =====
function cleanWebContent(text) {
  let result = text;

  // 1) Markdown-ссылки [текст](url) -> "текст"
  result = result.replace(/\[([^\]]+)]\((https?:\/\/[^\s)]+)\)/g, '$1');

  // 2) Голые URL (включая трекинговые)
  result = result.replace(/https?:\/\/\S+/g, '');

  // 3) Фильтр строк, похожих на навигацию/футер/авторизацию
  const navFooterPatterns = [
    'войти',
    'регистрация',
    'логин',
    'sign in',
    'sign up',
    'комментарии',
    'comments',
    'подписаться',
    'subscribe',
    'следующее',
    'previous',
    'next article',
    'related articles',
    'cookie',
    'privacy policy',
    'terms of use',
    'license',
    'share on',
    'поделиться',
    'facebook',
    'twitter',
    'instagram',
    'linkedin',
    'all rights reserved',
  ];

  result = result
    .split('\n')
    .filter(line => {
      const trimmed = line.trim();
      if (!trimmed) return true;

      const lower = trimmed.toLowerCase();

      // очень короткие "мусорные" строки без букв
      if (trimmed.length <= 3 && !/[a-zа-я]/i.test(trimmed)) return false;

      // навигация/футер/соцкнопки
      if (navFooterPatterns.some(p => lower.includes(p))) return false;

      return true;
    })
    .join('\n');

  // 4) Сжимаем пробелы и пустые строки
  result = result
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return result;
}

// ===== ОСНОВНАЯ ЛОГИКА =====
try {
  const title = extractTitle(content);
  const publicationDate = extractDate(content);
  const pdfUrl = extractPdfUrl(content);

  // ❌ ABSTRACT ОТКЛЮЧЕН - AI Agent сам сделает summary
  const abstract = null;

  const cleaned = cleanWebContent(content);

  return {
    json: {
      title,
      abstract,
      publicationDate,
      pdfUrl,
      cleanContent: cleaned,
      extracted: {
        hasTitle: !!title,
        hasAbstract: false,
        hasDate: !!publicationDate,
        hasPdf: !!pdfUrl,
      },
      metadata: {
        hasTitle: !!title,
        hasAbstract: false,
        hasDate: !!publicationDate,
        hasPdf: !!pdfUrl,
        contentLength: cleaned.length,
      },
    },
  };
} catch (error) {
  return {
    json: {
      title: null,
      abstract: null,
      publicationDate: null,
      pdfUrl: null,
      cleanContent: content,
      error: error.message,
      debug: {
        contentPreview: content.substring(0, 500),
      },
    },
  };
}

const item = $input.item.json;

// n8n возвращает ошибки в двух форматах:
// 1. item.error (старый формат)
// 2. item.errorMessage (новый формат от HTTP Request)

const hasError = item.error || item.errorMessage;

if (hasError) {
  // Извлекаем данные ошибки из разных форматов
  const errorMessage = item.errorMessage || item.error?.message || '';
  const errorDescription = item.errorDescription || '';
  const httpCode = item.errorDetails?.httpCode || item.error?.code || '';

  // Пытаемся распарсить rawErrorMessage для получения деталей
  let detailedMessage = errorDescription;
  if (item.errorDetails?.rawErrorMessage) {
    try {
      const raw = item.errorDetails.rawErrorMessage[0];
      const parsed = JSON.parse(raw.split(' - ')[1]);
      detailedMessage = parsed.message || parsed.readableMessage || errorDescription;
    } catch (e) {
      // Если не получилось распарсить - используем errorDescription
    }
  }

  let errorType = 'Ошибка получения контента';
  let errorDetails = '';
  let userMessage = '';

  // Классифицируем ошибки Jina
  if (detailedMessage.includes('could not be resolved')) {
    errorType = 'Неверная ссылка';
    errorDetails = 'Домен не существует или введена неправильная ссылка';
    userMessage = 'Проверьте правильность URL (возможно опечатка в адресе)';

  } else if (httpCode === '404' || detailedMessage.includes('not found')) {
    errorType = 'Страница не найдена';
    errorDetails = 'Страница удалена или URL неверный';
    userMessage = 'Проверьте ссылку или отправьте другую';

  } else if (httpCode === '403' || detailedMessage.includes('forbidden')) {
    errorType = 'Доступ запрещен';
    errorDetails = 'Требуется авторизация или контент защищен';
    userMessage = 'Попробуйте отправить PDF вместо ссылки';

  } else if (httpCode === '429' || detailedMessage.includes('rate limit')) {
    errorType = 'Превышен лимит запросов';
    errorDetails = 'Jina API временно ограничил доступ';
    userMessage = 'Попробуйте через минуту';

  } else if (detailedMessage.includes('timeout')) {
    errorType = 'Превышено время ожидания';
    errorDetails = 'Сайт слишком долго отвечает';
    userMessage = 'Попробуйте другую ссылку';

  } else {
    errorType = 'Не удалось обработать ссылку';
    errorDetails = detailedMessage || errorMessage;
    userMessage = 'Попробуйте отправить PDF или другую ссылку';
  }

   return {
    json: {
      ...item,
      hasError: true,
      errorType,
      errorDetails,
      userMessage,
      originalUrl: item.extractedUrl
    }
  };

}

// Если ошибки нет - возвращаем как есть
return {
  json: {
    ...item,
    hasError: false
  }
};

